fun id h => {
           intro id h
           rcases h with (h | h)
           · -- Case where the element is from `removed'`
             simp [h]
             <;> try { tauto }
           · -- Case where the element is from `state.satisfied` (but this is not `removed'`)
             simp [h] at *
             <;> try { tauto }
         }
       }
       exact result
     | none =>
       simp
       all_goals try { tauto }
   | none =>
     simp
     all_goals try { tauto }
